// items is the array of incoming webhook data
const allMessages = [];

// Loop through each incoming item
for (const item of items) {
  // Drill into the transcript array
  const transcript = item.json.body.data.transcript;

  // Collect any non-null message
  transcript.forEach(turn => {
    if (turn.message) {
      allMessages.push(turn.message.trim());
    }
  });
}

// Join them with a space (or any delimiter you like)
const combined = allMessages.join(' ');

// Return a single-item array with your result
return [
  {
    json: {
      combined,
    },
  },
];
